@dataclass
class NonceRecord:
    nonce: str
    created_at: float
    used: bool = False
    address: str = ""


@dataclass
class RateLimitRecord:
    timestamps: list = field(default_factory=list)


class NonceStore:
    """Secure nonce store with expiration and single-use enforcement."""

    def __init__(self):
        self._nonces: Dict[str, NonceRecord] = {}

    def generate_nonce(self, address: str) -> str:
        """Generate a cryptographically secure nonce for an address."""
        nonce = secrets.token_hex(32)
        normalized_address = Web3.to_checksum_address(address)

        # Invalidate any existing nonces for this address
        self._cleanup_address(normalized_address)

        self._nonces[nonce] = NonceRecord(
            nonce=nonce,
            created_at=time.time(),
            used=False,
            address=normalized_address
        )
        return nonce

    def validate_and_consume_nonce(self, nonce: str, address: str) -> bool:
        """Validate a nonce and mark it as consumed (single-use)."""
        self._cleanup_expired()

        record = self._nonces.get(nonce)
        if record is None:
            logger.warning("Nonce not found during validation")
            return False

        normalized_address = Web3.to_checksum_address(address)

        if record.used:
            logger.warning("Attempted reuse of consumed nonce for address: %s",
                           normalized_address[:10] + '...')
            # Remove the used nonce
            del self._nonces[nonce]
            return False

        if record.address != normalized_address:
            logger.warning("Nonce address mismatch")
            return False

        if time.time() - record.created_at > NONCE_EXPIRATION_SECONDS:
            logger.warning("Expired nonce used for address: %s",
                           normalized_address[:10] + '...')
            del self._nonces[nonce]
            return False

        # Mark as used and remove
        record.used = True
        del self._nonces[nonce]
        return True

    def _cleanup_expired(self):
        """Remove expired nonces."""
        current_time = time.time()
        expired = [
            k for k, v in self._nonces.items()
            if current_time - v.created_at > NONCE_EXPIRATION_SECONDS
        ]
        for k in expired:
            del self._nonces[k]

    def _cleanup_address(self, address: str):
        """Remove all nonces for a given address."""
        to_remove = [
            k for k, v in self._nonces.items()
            if v.address == address
        ]
        for k in to_remove:
            del self._nonces[k]


class RateLimiter:
    """Simple in-memory rate limiter."""

    def __init__(self):
        self._records: Dict[str, RateLimitRecord] = {}

    def is_rate_limited(self, key: str) -> bool:
        """Check if a key is rate limited."""
        current_time = time.time()
        record = self._records.get(key)

        if record is None:
            self._records[key] = RateLimitRecord(timestamps=[current_time])
            return False

        # Clean old timestamps
        record.timestamps = [
            ts for ts in record.timestamps
            if current_time - ts < RATE_LIMIT_WINDOW
        ]

        if len(record.timestamps) >= RATE_LIMIT_MAX_REQUESTS:
            return True

        record.timestamps.append(current_time)
        return False


# Initialize stores
nonce_store = NonceStore()
