def validate_ethereum_address(address: str) -> Optional[str]:
    """Validate and normalize an Ethereum address."""
    if not isinstance(address, str):
        return None

    # Check basic format
    if not re.match(r'^0x[0-9a-fA-F]{40}$', address):
        return None

    try:
        return Web3.to_checksum_address(address)
    except (ValueError, Exception):
        return None


def validate_signature_format(signature: str) -> bool:
    """Validate signature format."""
    if not isinstance(signature, str):
        return False
    return bool(re.match(r'^0x[0-9a-fA-F]{130}$', signature))


def validate_nonce_format(nonce: str) -> bool:
    """Validate nonce format."""
    if not isinstance(nonce, str):
        return False
    return bool(re.match(r'^[0-9a-f]{64}$', nonce))


def construct_sign_message(nonce: str, address: str, domain: str) -> str:
    """Construct a standardized message for signing.

    Uses a structured format to prevent signature reuse across different contexts.
    """
    timestamp = int(time.time())
    return (
        f"Sign this message to authenticate with {domain}\n\n"
        f"Address: {address}\n"
        f"Nonce: {nonce}\n"
        f"Chain ID: 1\n"
        f"Issued At: {datetime.utcnow().isoformat()}Z"
    )


def verify_signature(message: str, signature: str, expected_address: str) -> bool:
    """Verify an Ethereum signature and check the recovered address matches."""
    try:
        # Encode the message as per EIP-191
        encoded_message = encode_defunct(text=message)

        # Recover the address from the signature
        recovered_address = w3_auto.eth.account.recover_message(
            encoded_message,
            signature=signature
        )

        # Constant-time comparison to prevent timing attacks
        expected_normalized = Web3.to_checksum_address(expected_address)
        recovered_normalized = Web3.to_checksum_address(recovered_address)

        return secrets.compare_digest(
            expected_normalized.lower().encode(),
            recovered_normalized.lower().encode()
        )
    except Exception as e:
        logger.error("Signature verification failed: %s", type(e).__name__)
        return False


def generate_jwt_token(address: str) -> str:
    """Generate a JWT token for an authenticated address."""
    now = datetime.utcnow()
    token_id = secrets.token_hex(16)

    payload = {
        'sub': Web3.to_checksum_address(address),
        'iat': now,
        'exp': now + timedelta(hours=JWT_EXPIRATION_HOURS),
        'jti': token_id,
        'iss': 'web3-auth-service',
        'type': 'access'
    }

    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)


def verify_jwt_token(token: str) -> Optional[Dict[str, Any]]:
    """Verify and decode a JWT token."""
    try:
        payload = jwt.decode(
            token,
            JWT_SECRET,
            algorithms=[JWT_ALGORITHM],
            issuer='web3-auth-service',
            options={
                'require': ['sub', 'iat', 'exp', 'jti', 'iss', 'type'],
                'verify_exp': True,
                'verify_iss': True,
            }
        )

        # Check if token is revoked
        if payload.get('jti') in revoked_tokens:
            logger.warning("Attempted use of revoked token")
            return None

        # Validate the address in the token
        if not validate_ethereum_address(payload.get('sub', '')):
            return None

        if payload.get('type') != 'access':
            return None

        return payload
    except jwt.ExpiredSignatureError:
        logger.info("Expired JWT token presented")
        return None
    except jwt.InvalidTokenError as e:
        logger.warning("Invalid JWT token: %s", type(e).__name__)
        return None


def require_auth(f):
    """Decorator to require JWT authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')

        if not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid authorization header'}), 401

        token = auth_header[7:]  # Remove 'Bearer ' prefix

        # Basic token format validation
        if len(token) > 2048:
            return jsonify({'error': 'Invalid token'}), 401

        payload = verify_jwt_token(token)
        if payload is None:
            return jsonify({'error': 'Invalid or expired token'}), 401

        g.current_user = payload['sub']
        g.token_jti = payload['jti']
        return f(*args, **kwargs)

    return decorated


def get_client_identifier() -> str:
    """Get a client identifier for rate limiting."""
    # Use IP address (consider X-Forwarded-For in production behind a trusted proxy)
    forwarded = request.headers.get('X-Forwarded-For', '')
    if forwarded:
        # Only trust the first IP if behind a trusted reverse proxy
        ip = forwarded.split(',')[0].strip()
    else:
        ip = request.remote_addr or 'unknown'

    return hashlib.sha256(ip.encode()).hexdigest()[:16]


@app.before_request
def check_content_type():
    """Validate content type for POST/PUT requests."""
    if request.method in ('POST', 'PUT'):
        if not request.is_json:
            return jsonify({'error': 'Content-Type must be application/json'}), 415


@app.after_request
def set_security_headers(response):
    """Set security headers on all responses."""
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'
    response.headers['Content-Type'] = 'application/json'

    # CORS - only allow specified origins
    origin = request.headers.get('Origin', '')
    if origin in ALLOWED_ORIGINS:
        response.headers['Access-Control-Allow-Origin'] = origin
        response.headers['Access-Control-Allow-Methods'] = 'GET, POST, OPTIONS'
        response.headers['Access-Control-Allow-Headers'] = 'Content-Type, Authorization'
        response.headers['Access-Control-Max-Age'] = '3600'

    return response


@app.route('/auth/nonce', methods=['POST'])
def request_nonce():
    """Request a nonce for signing.

    Expects JSON: {"address": "0x..."}
    Returns: {"nonce": "...", "message": "..."}
    """
    client_id = get_client_identifier()
    if rate_limiter.is_rate_limited(f"nonce:{client_id}"):
        return jsonify({'error': 'Rate limit exceeded. Try again later.'}), 429

    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Invalid request body'}), 400

    address = data.get('address')
    if not address:
        return jsonify({'error': 'Address is required'}), 400

    # Validate address
    normalized_address = validate_ethereum_address(address)
    if normalized_address is None:
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    # Generate nonce
    nonce = nonce_store.generate_nonce(normalized_address)

    # Construct the message the user should sign
    domain = os.environ.get('AUTH_DOMAIN', 'Web3 Auth Service')
    message = construct_sign_message(nonce, normalized_address, domain)

    logger.info("Nonce generated for address: %s...", normalized_address[:10])

    return jsonify({
        'nonce': nonce,
        'message': message,
        'expires_in': NONCE_EXPIRATION_SECONDS
    }), 200


@app.route('/auth/verify', methods=['POST'])
def verify_and_authenticate():
    """Verify a signed message and issue a JWT token.

    Expects JSON: {"address": "0x...", "signature": "0x...", "nonce": "...", "message": "..."}
    Returns: {"token": "...", "address": "0x...", "expires_in": ...}
    """
    client_id = get_client_identifier()
    if rate_limiter.is_rate_limited(f"verify:{client_id}"):
        return jsonify({'error': 'Rate limit exceeded. Try again later.'}), 429

    data = request.get_json(silent=True)
    if not data:
        return jsonify({'error': 'Invalid request body'}), 400

    address = data.get('address')
    signature = data.get('signature')
    nonce = data.get('nonce')
    message = data.get('message')

    # Validate all required fields
    if not all([address, signature, nonce, message]):
        return jsonify({'error': 'Missing required fields: address, signature, nonce, message'}), 400

    # Validate address
    normalized_address = validate_ethereum_address(address)
    if normalized_address is None:
        return jsonify({'error': 'Invalid Ethereum address'}), 400

    # Validate signature format
    if not validate_signature_format(signature):
        return jsonify({'error': 'Invalid signature format'}), 400

    # Validate nonce format
    if not validate_nonce_format(nonce):
        return jsonify({'error': 'Invalid nonce format'}), 400

    # Validate message length
    if not isinstance(message, str) or len(message) > MAX_MESSAGE_LENGTH:
        return jsonify({'error': 'Invalid message'}), 400

    # Validate and consume the nonce (single-use)
    if not nonce_store.validate_and_consume_nonce(nonce, normalized_address):
        logger.warning("Invalid or expired nonce for address: %s...", normalized_address[:10])
        return jsonify({'error': 'Invalid, expired, or already used nonce'}), 401

    # Reconstruct expected message and verify it matches
    domain = os.environ.get('AUTH_DOMAIN', 'Web3 Auth Service')
    # We verify the nonce is in the message to prevent message substitution
    if nonce not in message or normalized_address not in message:
        logger.warning("Message content mismatch for address: %s...", normalized_address[:10])
        return jsonify({'error': 'Message content mismatch'}), 401

    # Verify the signature
    if not verify_signature(message, signature, normalized_address):
        logger.warning("Signature verification failed for address: %s...",
                        normalized_address[:10])
        return jsonify({'error': 'Signature verification failed'}), 401

    # Generate JWT token
    token = generate_jwt_token(normalized_address)

    logger.info("Successful authentication for address: %s...", normalized_address[:10])

    return jsonify({
        'token': token,
        'address': normalized_address,
        'expires_in': JWT_EXPIRATION_HOURS * 3600,
        'token_type': 'Bearer'
    }), 200


@app.route('/auth/refresh', methods=['POST'])
@require_auth
def refresh_token():
    """Refresh an existing valid JWT token."""
    client_id = get_client_identifier()
    if rate_limiter.is_rate_limited(f"refresh:{client_id}"):
        return jsonify({'error': 'Rate limit exceeded. Try again later.'}), 429

    # Revoke the old token
    revoked_tokens.add(g.token_jti)

    # Issue a new token
    new_token = generate_jwt_token(g.current_user)

    logger.info("Token refreshed for address: %s...", g.current_user[:10])

    return jsonify({
        'token': new_token,
        'address': g.current_user,
        'expires_in': JWT_EXPIRATION_HOURS * 3600,
        'token_type': 'Bearer'
    }), 200


@app.route('/auth/logout', methods=['POST'])
@require_auth
def logout():
    """Revoke the current JWT token."""
    revoked_tokens.add(g.token_jti)

    logger.info("Token revoked for address: %s...", g.current_user[:10])

    return jsonify({'message': 'Successfully logged out'}), 200


